-- Migration: add category column if it doesn't exist
DO $$ 
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_name='desserts' AND column_name='category'
    ) THEN
        ALTER TABLE desserts ADD COLUMN category VARCHAR(50) DEFAULT 'other';
    END IF;
END $$;

-- Re-seed all desserts with correct categories
TRUNCATE TABLE desserts RESTART IDENTITY CASCADE;

